head.b:skin:
/* ═══════════════════════════════════════════════════
   AIVENXLAB THEME — DEBIAN UI STYLE
   Dark • Mono • Technical • Professional
   ═══════════════════════════════════════════════════ */

:root {
  /* Core Palette — GitHub Dark × Debian */
  --bg-base:        #0d1117;
  --bg-secondary:   #161b22;
  --bg-tertiary:    #1c2128;
  --bg-card:        #13181f;
  --bg-hover:       #1f2937;
  --border:         #21262d;
  --border-muted:   #30363d;

  /* Text */
  --text-primary:   #e6edf3;
  --text-secondary: #8b949e;
  --text-muted:     #484f58;
  --text-code:      #f0883e;

  /* Accents */
  --accent-blue:    #58a6ff;
  --accent-green:   #3fb950;
  --accent-orange:  #d29922;
  --accent-red:     #f85149;
  --accent-purple:  #bc8cff;
  --accent-cyan:    #39c5cf;

  /* Debian Specific */
  --debian-red:     #d70a53;
  --debian-gray:    #a80030;

  /* Typography */
  --font-sans:      'Space Grotesk', sans-serif;
  --font-mono:      'JetBrains Mono', monospace;
  --font-display:   'Syne', sans-serif;

  /* Sizing */
  --radius-sm:      4px;
  --radius-md:      8px;
  --radius-lg:      12px;
  --max-width:      1200px;
  --sidebar-width:  300px;

  /* Shadows */
  --shadow-sm:      0 1px 3px rgba(0,0,0,0.4);
  --shadow-md:      0 4px 16px rgba(0,0,0,0.5);
  --shadow-lg:      0 8px 32px rgba(0,0,0,0.6);
  --glow-blue:      0 0 20px rgba(88,166,255,0.15);
  --glow-red:       0 0 20px rgba(215,10,83,0.15);
}

/* ═══ RESET & BASE ═══ */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; font-size: 16px; }

body {
  background-color: var(--bg-base);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 15px;
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
  background-image:
    radial-gradient(ellipse 80% 50% at 50% -20%, rgba(88,166,255,0.08) 0%, transparent 60%),
    linear-gradient(180deg, var(--bg-base) 0%, #0a0f16 100%);
  min-height: 100vh;
}

a { color: var(--accent-blue); text-decoration: none; transition: color 0.2s; }
a:hover { color: var(--accent-cyan); }

img { max-width: 100%; height: auto; display: block; }

/* ═══ SCANLINE TEXTURE ═══ */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  background-image: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(0,0,0,0.03) 2px,
    rgba(0,0,0,0.03) 4px
  );
  pointer-events: none;
  z-index: 0;
}

/* ═══ TOP ANNOUNCEMENT BAR ═══ */
#topbar {
  background: linear-gradient(90deg, var(--debian-red), #a80030, var(--debian-red));
  background-size: 200% 100%;
  animation: barFlow 8s linear infinite;
  color: #fff;
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.15em;
  text-align: center;
  padding: 6px 20px;
  border-bottom: 1px solid rgba(255,255,255,0.1);
  position: relative;
  z-index: 100;
}

@keyframes barFlow {
  0% { background-position: 0% 50%; }
  100% { background-position: 200% 50%; }
}

/* ═══ HEADER ═══ */
#header-wrapper {
  position: sticky;
  top: 0;
  z-index: 99;
  background: rgba(13,17,23,0.92);
  backdrop-filter: blur(20px) saturate(150%);
  -webkit-backdrop-filter: blur(20px) saturate(150%);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 1px 0 rgba(255,255,255,0.04);
}

#header-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
  gap: 24px;
}

/* Logo */
.header-logo {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-shrink: 0;
}

.logo-icon {
  width: 38px;
  height: 38px;
  background: linear-gradient(135deg, var(--debian-red), #ff4080);
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-mono);
  font-weight: 700;
  font-size: 14px;
  color: #fff;
  box-shadow: var(--glow-red), inset 0 1px 0 rgba(255,255,255,0.15);
  flex-shrink: 0;
}

.logo-text-wrap { display: flex; flex-direction: column; line-height: 1; }

.logo-name {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 800;
  color: var(--text-primary);
  letter-spacing: -0.03em;
}

.logo-name span { color: var(--accent-blue); }

.logo-tagline {
  font-family: var(--font-mono);
  font-size: 9px;
  color: var(--text-muted);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  margin-top: 2px;
}

/* Nav */
.header-nav {
  display: flex;
  align-items: center;
  gap: 4px;
}

.header-nav a {
  color: var(--text-secondary);
  font-size: 13px;
  font-weight: 500;
  padding: 6px 12px;
  border-radius: var(--radius-sm);
  transition: all 0.2s;
  border: 1px solid transparent;
  white-space: nowrap;
}

.header-nav a:hover {
  color: var(--text-primary);
  background: var(--bg-secondary);
  border-color: var(--border-muted);
}

/* Search */
.header-search {
  display: flex;
  align-items: center;
  gap: 8px;
}

.header-search form {
  display: flex;
  align-items: center;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  overflow: hidden;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.header-search form:focus-within {
  border-color: var(--accent-blue);
  box-shadow: 0 0 0 3px rgba(88,166,255,0.12);
}

.header-search input {
  background: transparent;
  border: none;
  outline: none;
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-size: 12px;
  padding: 8px 14px;
  width: 180px;
}

.header-search input::placeholder { color: var(--text-muted); }

.header-search button {
  background: var(--accent-blue);
  border: none;
  color: var(--bg-base);
  cursor: pointer;
  padding: 8px 14px;
  font-size: 12px;
  font-weight: 600;
  transition: background 0.2s;
}

.header-search button:hover { background: var(--accent-cyan); }

/* Mobile menu toggle */
.mobile-toggle {
  display: none;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text-primary);
  cursor: pointer;
  padding: 8px 10px;
  font-size: 16px;
}

/* ═══ HERO (Homepage) ═══ */
.hero-section {
  max-width: var(--max-width);
  margin: 48px auto 0;
  padding: 0 24px 48px;
  text-align: center;
  position: relative;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(88,166,255,0.1);
  border: 1px solid rgba(88,166,255,0.25);
  color: var(--accent-blue);
  font-family: var(--font-mono);
  font-size: 11px;
  letter-spacing: 0.12em;
  padding: 5px 14px;
  border-radius: 20px;
  margin-bottom: 20px;
  text-transform: uppercase;
}

.hero-badge::before {
  content: '';
  width: 6px; height: 6px;
  background: var(--accent-green);
  border-radius: 50%;
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.5; transform: scale(0.8); }
}

.hero-title {
  font-family: var(--font-display);
  font-size: clamp(36px, 6vw, 72px);
  font-weight: 800;
  line-height: 1.05;
  letter-spacing: -0.04em;
  margin-bottom: 16px;
  background: linear-gradient(135deg, var(--text-primary) 0%, var(--accent-blue) 50%, var(--accent-cyan) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-sub {
  color: var(--text-secondary);
  font-size: 16px;
  max-width: 500px;
  margin: 0 auto 32px;
  font-family: var(--font-mono);
}

.hero-cta {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: linear-gradient(135deg, var(--debian-red), #ff4080);
  color: #fff;
  font-weight: 600;
  font-size: 14px;
  padding: 12px 28px;
  border-radius: var(--radius-md);
  transition: transform 0.2s, box-shadow 0.2s;
  box-shadow: 0 4px 16px rgba(215,10,83,0.4);
}

.hero-cta:hover {
  color: #fff;
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(215,10,83,0.5);
}

/* ═══ MAIN LAYOUT ═══ */
.outer-wrapper {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 24px 80px;
  display: grid;
  grid-template-columns: 1fr var(--sidebar-width);
  gap: 32px;
  align-items: start;
}

/* ═══ SECTION LABEL ═══ */
.section-label {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 24px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}

.section-label h2 {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
}

.section-label::before {
  content: '';
  width: 3px;
  height: 14px;
  background: var(--accent-blue);
  border-radius: 2px;
  flex-shrink: 0;
}

/* ═══ POST CARDS ═══ */
.blog-posts { display: flex; flex-direction: column; gap: 0; }

.post-outer {
  border-bottom: 1px solid var(--border);
  padding: 28px 0;
  transition: background 0.2s;
  position: relative;
}

.post-outer:first-child { border-top: none; padding-top: 0; }

.post-outer:hover::before {
  content: '';
  position: absolute;
  left: -24px;
  top: 0; bottom: 0;
  width: 3px;
  background: var(--accent-blue);
  border-radius: 0 2px 2px 0;
}

.post-header { display: flex; align-items: flex-start; gap: 16px; }

.post-thumbnail {
  width: 160px;
  height: 105px;
  flex-shrink: 0;
  border-radius: var(--radius-md);
  overflow: hidden;
  background: var(--bg-secondary);
  border: 1px solid var(--border);
}

.post-thumbnail img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s;
}

.post-outer:hover .post-thumbnail img { transform: scale(1.06); }

.post-content { flex: 1; min-width: 0; }

.post-meta-top {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
  flex-wrap: wrap;
}

.post-label {
  background: rgba(88,166,255,0.12);
  color: var(--accent-blue);
  font-family: var(--font-mono);
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.1em;
  padding: 3px 10px;
  border-radius: 20px;
  border: 1px solid rgba(88,166,255,0.2);
  text-transform: uppercase;
}

.post-date {
  color: var(--text-muted);
  font-family: var(--font-mono);
  font-size: 11px;
}

.post-title {
  font-family: var(--font-display);
  font-size: 19px;
  font-weight: 700;
  line-height: 1.3;
  letter-spacing: -0.02em;
  margin-bottom: 10px;
}

.post-title a {
  color: var(--text-primary);
  transition: color 0.2s;
}

.post-title a:hover { color: var(--accent-blue); }

.post-snippet {
  color: var(--text-secondary);
  font-size: 13.5px;
  line-height: 1.65;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 14px;
}

.post-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.post-author {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-muted);
  font-size: 12px;
  font-family: var(--font-mono);
}

.author-avatar {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--debian-red), var(--accent-purple));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 9px;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
}

.read-more {
  color: var(--accent-blue);
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.08em;
  display: flex;
  align-items: center;
  gap: 4px;
  transition: gap 0.2s;
}

.read-more:hover { color: var(--accent-cyan); gap: 8px; }

/* ═══ FEATURED POST (first) ═══ */
.post-outer:first-child .post-thumbnail {
  width: 100%;
  height: 220px;
  margin-bottom: 16px;
}

.post-outer:first-child .post-header { flex-direction: column; }

.post-outer:first-child .post-title { font-size: 26px; }

/* ═══ PAGINATION ═══ */
.blog-pager {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 28px 0;
  border-top: 1px solid var(--border);
  margin-top: 8px;
}

.blog-pager a {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: var(--bg-secondary);
  border: 1px solid var(--border-muted);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 12px;
  padding: 8px 18px;
  border-radius: var(--radius-md);
  transition: all 0.2s;
}

.blog-pager a:hover {
  border-color: var(--accent-blue);
  color: var(--accent-blue);
  background: rgba(88,166,255,0.08);
}

/* ═══ SIDEBAR ═══ */
#sidebar-wrapper { position: sticky; top: 88px; }

.sidebar-widget {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin-bottom: 20px;
  box-shadow: var(--shadow-sm);
  transition: border-color 0.2s;
}

.sidebar-widget:hover { border-color: var(--border-muted); }

.widget-title {
  font-family: var(--font-mono);
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
  padding: 14px 16px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 8px;
}

.widget-title::before {
  content: '//';
  color: var(--accent-blue);
  font-weight: 700;
}

.widget-body { padding: 16px; }

/* About Widget */
.about-widget-avatar {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--debian-red), var(--accent-blue));
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-mono);
  font-size: 22px;
  font-weight: 700;
  color: #fff;
  margin: 0 auto 12px;
  box-shadow: 0 0 0 3px var(--border), var(--glow-red);
}

.about-widget-name {
  text-align: center;
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: 700;
  color: var(--text-primary);
  margin-bottom: 4px;
}

.about-widget-slogan {
  text-align: center;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.08em;
  margin-bottom: 12px;
}

.about-widget-desc {
  font-size: 12.5px;
  color: var(--text-secondary);
  text-align: center;
  line-height: 1.6;
}

/* Social Links */
.social-links {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  margin-top: 14px;
}

.social-link {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 8px;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-secondary);
  transition: all 0.2s;
}

.social-link:hover {
  border-color: var(--accent-blue);
  color: var(--accent-blue);
  background: rgba(88,166,255,0.06);
}

/* Labels Widget */
.label-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.label-list a {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 10px;
  padding: 4px 10px;
  border-radius: 20px;
  transition: all 0.2s;
}

.label-list a:hover {
  background: rgba(88,166,255,0.1);
  border-color: var(--accent-blue);
  color: var(--accent-blue);
}

/* Popular Posts Widget */
.popular-posts ul { list-style: none; }

.popular-posts li {
  padding: 10px 0;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: flex-start;
  gap: 10px;
}

.popular-posts li:last-child { border-bottom: none; padding-bottom: 0; }

.popular-rank {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 700;
  color: var(--text-muted);
  min-width: 20px;
  padding-top: 2px;
}

.popular-posts li:nth-child(1) .popular-rank { color: var(--accent-orange); }
.popular-posts li:nth-child(2) .popular-rank { color: var(--text-secondary); }
.popular-posts li:nth-child(3) .popular-rank { color: var(--text-code); }

.popular-posts a {
  color: var(--text-secondary);
  font-size: 12.5px;
  line-height: 1.5;
  transition: color 0.2s;
}

.popular-posts a:hover { color: var(--accent-blue); }

/* Archive Widget */
.archive-list { list-style: none; }

.archive-list li {
  border-bottom: 1px solid var(--border);
}

.archive-list li:last-child { border-bottom: none; }

.archive-list a {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 9px 0;
  color: var(--text-secondary);
  font-size: 13px;
  transition: color 0.2s;
}

.archive-list a:hover { color: var(--accent-blue); }

.archive-count {
  background: var(--bg-tertiary);
  color: var(--text-muted);
  font-family: var(--font-mono);
  font-size: 10px;
  padding: 2px 7px;
  border-radius: 10px;
  border: 1px solid var(--border);
}

/* AdSense Sidebar Widget */
.adsense-widget {
  background: var(--bg-secondary);
  border: 1px dashed var(--border-muted);
  border-radius: var(--radius-lg);
  padding: 12px;
  text-align: center;
  margin-bottom: 20px;
}

.adsense-label {
  font-family: var(--font-mono);
  font-size: 9px;
  color: var(--text-muted);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  margin-bottom: 8px;
}

/* ═══ SINGLE POST VIEW ═══ */
.post-body-wrapper {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin-bottom: 28px;
  box-shadow: var(--shadow-md);
}

.post-cover {
  width: 100%;
  max-height: 400px;
  object-fit: cover;
  border-bottom: 1px solid var(--border);
}

.post-body-inner { padding: 36px 40px; }

.post-body-title {
  font-family: var(--font-display);
  font-size: clamp(26px, 4vw, 40px);
  font-weight: 800;
  line-height: 1.2;
  letter-spacing: -0.03em;
  color: var(--text-primary);
  margin-bottom: 16px;
}

.post-meta {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 28px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
  flex-wrap: wrap;
}

.post-meta-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

.post-meta-item span { color: var(--text-secondary); }

/* Post Body Typography */
.post-body h2, .post-body h3, .post-body h4 {
  font-family: var(--font-display);
  color: var(--text-primary);
  margin: 28px 0 14px;
  letter-spacing: -0.02em;
}

.post-body h2 {
  font-size: 24px;
  font-weight: 700;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--border);
}

.post-body h3 { font-size: 18px; font-weight: 600; }
.post-body h4 { font-size: 15px; font-weight: 600; color: var(--text-secondary); }

.post-body p {
  color: var(--text-secondary);
  font-size: 15px;
  line-height: 1.8;
  margin-bottom: 18px;
}

.post-body ul, .post-body ol {
  color: var(--text-secondary);
  padding-left: 24px;
  margin-bottom: 18px;
  line-height: 1.8;
}

.post-body li { margin-bottom: 6px; }

.post-body a {
  color: var(--accent-blue);
  border-bottom: 1px solid rgba(88,166,255,0.3);
  transition: border-color 0.2s;
}

.post-body a:hover { border-color: var(--accent-blue); }

.post-body img {
  border-radius: var(--radius-md);
  border: 1px solid var(--border);
  margin: 20px auto;
}

.post-body blockquote {
  border-left: 3px solid var(--accent-blue);
  background: rgba(88,166,255,0.06);
  padding: 16px 20px;
  margin: 20px 0;
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  color: var(--text-secondary);
  font-style: italic;
}

.post-body pre {
  background: var(--bg-base);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 20px;
  overflow-x: auto;
  margin: 20px 0;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.7;
  color: var(--text-code);
  position: relative;
}

.post-body pre::before {
  content: '$ ';
  color: var(--accent-green);
  opacity: 0.7;
}

.post-body code {
  font-family: var(--font-mono);
  font-size: 12.5px;
  color: var(--text-code);
  background: rgba(240,136,62,0.1);
  padding: 2px 6px;
  border-radius: 3px;
  border: 1px solid rgba(240,136,62,0.2);
}

.post-body pre code {
  background: transparent;
  border: none;
  padding: 0;
  color: inherit;
}

/* Post Tags */
.post-tags {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
  margin-top: 28px;
  padding-top: 20px;
  border-top: 1px solid var(--border);
}

.post-tag {
  display: inline-flex;
  align-items: center;
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  font-family: var(--font-mono);
  font-size: 11px;
  padding: 4px 12px;
  border-radius: 20px;
  transition: all 0.2s;
}

.post-tag:hover {
  background: rgba(88,166,255,0.1);
  border-color: var(--accent-blue);
  color: var(--accent-blue);
}

/* Post Share */
.post-share {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 16px;
  padding: 16px 20px;
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
}

.post-share-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  flex-shrink: 0;
}

.share-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 6px 14px;
  border-radius: var(--radius-sm);
  font-size: 11px;
  font-family: var(--font-mono);
  transition: all 0.2s;
  cursor: pointer;
}

.share-twitter { background: rgba(29,161,242,0.1); color: #1da1f2; border: 1px solid rgba(29,161,242,0.25); }
.share-facebook { background: rgba(66,103,178,0.1); color: #4267b2; border: 1px solid rgba(66,103,178,0.25); }
.share-copy { background: rgba(88,166,255,0.1); color: var(--accent-blue); border: 1px solid rgba(88,166,255,0.25); }

.share-btn:hover { opacity: 0.85; transform: translateY(-1px); }

/* In-Article AdSense */
.in-article-ad {
  text-align: center;
  margin: 28px 0;
  padding: 16px;
  background: var(--bg-tertiary);
  border: 1px dashed var(--border-muted);
  border-radius: var(--radius-md);
}

.in-article-ad-label {
  font-family: var(--font-mono);
  font-size: 9px;
  color: var(--text-muted);
  letter-spacing: 0.1em;
  text-transform: uppercase;
  margin-bottom: 8px;
}

/* ═══ COMMENTS ═══ */
#comments {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 28px 32px;
  margin-bottom: 28px;
}

#comments h4 {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  margin-bottom: 20px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}

.comment-block {
  padding: 16px 0;
  border-bottom: 1px solid var(--border);
  display: flex;
  gap: 14px;
}

.comment-block:last-of-type { border-bottom: none; }

.comment-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--bg-tertiary), var(--border));
  flex-shrink: 0;
  overflow: hidden;
}

.comment-content { flex: 1; min-width: 0; }

.comment-author-name {
  font-weight: 600;
  font-size: 13px;
  color: var(--text-primary);
  margin-bottom: 2px;
}

.comment-date {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  margin-bottom: 8px;
}

.comment-text {
  font-size: 13.5px;
  color: var(--text-secondary);
  line-height: 1.65;
}

/* ═══ RELATED POSTS ═══ */
.related-posts {
  background: var(--bg-secondary);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 28px;
}

.related-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 16px;
  margin-top: 16px;
}

.related-card {
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  overflow: hidden;
  transition: all 0.2s;
}

.related-card:hover {
  border-color: var(--border-muted);
  transform: translateY(-2px);
  box-shadow: var(--shadow-sm);
}

.related-card-img {
  width: 100%;
  height: 90px;
  object-fit: cover;
  background: var(--bg-base);
  border-bottom: 1px solid var(--border);
}

.related-card-content { padding: 12px; }

.related-card-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-secondary);
  line-height: 1.4;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  transition: color 0.2s;
}

.related-card:hover .related-card-title { color: var(--accent-blue); }

/* ═══ FOOTER ═══ */
#footer-wrapper {
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  margin-top: 40px;
}

.footer-top {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 56px 24px 40px;
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 40px;
}

.footer-brand .logo-name {
  font-size: 22px;
  margin-bottom: 12px;
}

.footer-brand .logo-tagline {
  font-size: 10px;
  margin-bottom: 16px;
}

.footer-desc {
  color: var(--text-muted);
  font-size: 13px;
  line-height: 1.7;
  max-width: 280px;
}

.footer-col-title {
  font-family: var(--font-mono);
  font-size: 10px;
  font-weight: 500;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 14px;
}

.footer-links { list-style: none; }

.footer-links li { margin-bottom: 8px; }

.footer-links a {
  color: var(--text-muted);
  font-size: 13px;
  transition: color 0.2s;
}

.footer-links a:hover { color: var(--accent-blue); }

.footer-bottom {
  border-top: 1px solid var(--border);
  padding: 18px 24px;
}

.footer-bottom-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

.footer-copy {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

.footer-copy a { color: var(--accent-blue); }

.footer-built {
  font-family: var(--font-mono);
  font-size: 10px;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  gap: 6px;
}

.footer-built::before {
  content: '';
  width: 6px; height: 6px;
  background: var(--accent-green);
  border-radius: 50%;
  animation: pulse 3s infinite;
}

/* ═══ NOTIFICATION BAR ═══ */
.notification-bar {
  position: fixed;
  bottom: 24px;
  right: 24px;
  z-index: 500;
  background: var(--bg-secondary);
  border: 1px solid var(--accent-blue);
  border-radius: var(--radius-md);
  padding: 14px 18px;
  max-width: 300px;
  box-shadow: var(--shadow-lg), var(--glow-blue);
  display: none;
  animation: slideIn 0.3s ease;
}

@keyframes slideIn {
  from { transform: translateY(20px); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}

/* ═══ LOADING BAR ═══ */
#nprogress {
  position: fixed;
  top: 0; left: 0;
  width: 0%;
  height: 2px;
  background: linear-gradient(90deg, var(--accent-blue), var(--accent-cyan));
  z-index: 9999;
  transition: width 0.3s;
}

/* ═══ SCROLL TO TOP ═══ */
#scrolltop {
  position: fixed;
  bottom: 28px;
  right: 28px;
  width: 40px;
  height: 40px;
  background: var(--bg-secondary);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: var(--text-secondary);
  font-size: 16px;
  transition: all 0.2s;
  opacity: 0;
  pointer-events: none;
  z-index: 200;
  box-shadow: var(--shadow-sm);
}

#scrolltop.visible {
  opacity: 1;
  pointer-events: auto;
}

#scrolltop:hover {
  background: var(--accent-blue);
  border-color: var(--accent-blue);
  color: var(--bg-base);
  transform: translateY(-3px);
}

/* ═══ BREADCRUMBS ═══ */
.breadcrumb {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 12px 24px;
  display: flex;
  align-items: center;
  gap: 6px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

.breadcrumb a { color: var(--text-muted); }
.breadcrumb a:hover { color: var(--accent-blue); }
.breadcrumb .sep { color: var(--border-muted); }
.breadcrumb .current { color: var(--text-secondary); }

/* ═══ ERROR PAGE ═══ */
.error-page {
  text-align: center;
  padding: 80px 24px;
}

.error-code {
  font-family: var(--font-mono);
  font-size: 96px;
  font-weight: 800;
  color: var(--border-muted);
  line-height: 1;
  margin-bottom: 16px;
}

.error-msg {
  font-family: var(--font-display);
  font-size: 22px;
  color: var(--text-primary);
  margin-bottom: 12px;
}

.error-sub {
  color: var(--text-secondary);
  margin-bottom: 32px;
  font-family: var(--font-mono);
  font-size: 13px;
}

/* ═══ UTILITIES ═══ */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
}

/* ═══ RESPONSIVE ═══ */
@media (max-width: 1024px) {
  .outer-wrapper {
    grid-template-columns: 1fr;
  }

  #sidebar-wrapper {
    position: static;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 16px;
  }

  .footer-top {
    grid-template-columns: 1fr 1fr;
    gap: 28px;
  }
}

@media (max-width: 768px) {
  :root { --max-width: 100%; }

  #header-inner { height: 56px; padding: 0 16px; }

  .header-nav { display: none; }
  .header-nav.open {
    display: flex;
    flex-direction: column;
    position: absolute;
    top: 56px;
    left: 0; right: 0;
    background: var(--bg-secondary);
    border-bottom: 1px solid var(--border);
    padding: 12px 16px;
    gap: 2px;
    z-index: 98;
  }

  .mobile-toggle { display: flex; }

  .header-search { display: none; }

  .outer-wrapper { padding: 0 16px 60px; }

  .post-thumbnail { width: 110px; height: 75px; }
  .post-outer:first-child .post-thumbnail { height: 160px; }
  .post-outer:first-child .post-title { font-size: 20px; }

  .post-body-inner { padding: 24px 20px; }

  .footer-top { grid-template-columns: 1fr; gap: 24px; }

  .footer-bottom-inner { flex-direction: column; text-align: center; }

  #sidebar-wrapper { grid-template-columns: 1fr; }

  .hero-section { margin-top: 28px; }
}

@media (max-width: 480px) {
  .post-header { flex-direction: column; }
  .post-thumbnail { width: 100%; height: 140px; }
  .post-outer:first-child .post-thumbnail { height: 140px; }
}

/* ═══ PRINT STYLES ═══ */
@media print {
  #topbar, #header-wrapper, #sidebar-wrapper, #footer-wrapper,
  #scrolltop, .post-share, .related-posts, .in-article-ad { display: none !important; }

  .outer-wrapper { display: block; }
  .post-body-wrapper { border: none; box-shadow: none; }
  body { background: #fff; color: #000; }
}

/* ═══ CUSTOM SCROLLBAR ═══ */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: var(--bg-base); }
::-webkit-scrollbar-thumb { background: var(--border-muted); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }

/* ═══ SELECTION ═══ */
::selection {
  background: rgba(88,166,255,0.25);
  color: var(--text-primary);
}

body.script:
//

// Scroll to top
(function() {
  var btn = document.getElementById('scrolltop');
  window.addEventListener('scroll', function() {
    btn.classList.toggle('visible', window.scrollY > 400);
  });
  btn.addEventListener('click', function() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
})();

// Mobile nav toggle
(function() {
  var toggle = document.getElementById('mobile-toggle');
  var nav = document.getElementById('main-nav');
  if (toggle && nav) {
    toggle.addEventListener('click', function() {
      nav.classList.toggle('open');
      toggle.textContent = nav.classList.contains('open') ? '✕' : '☰';
    });
  }
})();

// Page load progress bar
(function() {
  var bar = document.getElementById('nprogress');
  if (!bar) return;
  var w = 0;
  bar.style.width = '30%';
  var t = setInterval(function() {
    w = Math.min(w + Math.random() * 20, 90);
    bar.style.width = w + '%';
  }, 200);
  window.addEventListener('load', function() {
    clearInterval(t);
    bar.style.width = '100%';
    bar.style.opacity = '0';
    setTimeout(function() { bar.style.display = 'none'; }, 400);
  });
})();

// Lazy image fade-in
(function() {
  if ('IntersectionObserver' in window) {
    var imgs = document.querySelectorAll('img[loading="lazy"]');
    imgs.forEach(function(img) {
      img.style.opacity = '0';
      img.style.transition = 'opacity 0.4s';
      var obs = new IntersectionObserver(function(entries) {
        entries.forEach(function(e) {
          if (e.isIntersecting) {
            e.target.style.opacity = '1';
            obs.unobserve(e.target);
          }
        });
      }, { threshold: 0.1 });
      obs.observe(img);
    });
  }
})();

// Code block copy button
(function() {
  document.querySelectorAll('pre').forEach(function(pre) {
    var btn = document.createElement('button');
    btn.textContent = 'copy';
    btn.style.cssText = 'position:absolute;top:10px;right:10px;background:rgba(88,166,255,0.15);border:1px solid rgba(88,166,255,0.3);color:#58a6ff;font-family:JetBrains Mono,monospace;font-size:10px;padding:3px 10px;border-radius:4px;cursor:pointer;transition:all 0.2s;letter-spacing:0.08em;';
    btn.addEventListener('click', function() {
      navigator.clipboard.writeText(pre.innerText.replace(/^\$ /,''));
      btn.textContent = '✓ copied';
      setTimeout(function() { btn.textContent = 'copy'; }, 2000);
    });
    pre.appendChild(btn);
  });
})();

//
